1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { type: "quote"; items: Item[] };
12	type Scenario = { steps: QuoteStep[] };
13	
14	export function runScenario(scenario: unknown): { results: unknown[] } {
15	  const { steps } = scenario as Scenario;
16	  const items = steps[0].items;
17	  const base = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
18	  const premium = base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
19	  return { results: [{ premium }] };
20	}
